3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const isAlive = (count: number, wasAlive: boolean): boolean =>
15	  count === 3 || (count === 2 && wasAlive);
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  const liveKeys = new Set(liveCells.map(cellKey));
19	  const counts = new Map<string, { cell: Cell; count: number }>();
20	  for (const cell of liveCells) {
21	    for (const neighbor of neighborsOf(cell)) {
22	      const key = cellKey(neighbor);
23	      const entry = counts.get(key) ?? { cell: neighbor, count: 0 };
24	      entry.count += 1;
25	      counts.set(key, entry);
26	    }
27	  }
28	  return [...counts].flatMap(([key, { cell, count }]) =>
29	    isAlive(count, liveKeys.has(key)) ? [cell] : []
30	  );
31	}
