export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const candidates = liveCells.flatMap(neighborsOf);
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of candidates) {
    const key = cellKey(cell);
    const prev = counts.get(key);
    counts.set(key, { cell, count: (prev?.count ?? 0) + 1 });
  }
  return [...counts.values()].flatMap(({ cell, count }) =>
    isAlive(count, liveKeys.has(cellKey(cell))) ? [cell] : []
  );
}

